#include <iostream>
#include <vector>

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> v(n);
    for (int i = 0; i < n; ++i)
        std::cin >> v[i];

    int sum = 0;
    for (auto it = v.begin(); it != v.end(); ++it)
        sum += *it;

    std::cout << "Sum: " << sum << '\n';
    return 0;
}

