solution_code:
#include <iostream>
#include <vector>

auto findFirst(const std::vector<int>& v, int target)
{
    for (auto it = v.begin(); it != v.end(); ++it)
        if (*it == target)
            return it;
    return v.end();
}

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> v(n);
    for (int i = 0; i < n; ++i)
        std::cin >> v[i];
    int target;
    std::cin >> target;

    auto it = findFirst(v, target);
    if (it != v.end())
        std::cout << "Found: " << (it - v.begin()) << '\n';
    else
        std::cout << "Not found\n";

    return 0;
}
